func (s *Service) CaptureBookmark(ctx context.Context, ownerID uuid.UUID, input BookmarkInput) (*Item, error) {
	if input.URL == "" {
		return nil, fmt.Errorf("item: capture bookmark: url is required")
	}
	if input.Source == "" {
		input.Source = "api"
	}
	if input.Sensitivity == "" {
		input.Sensitivity = "normal"
	}

	tags := input.Tags
	if tags == nil {
		tags = []string{}
	}

	metadata := buildBookmarkMetadata(input.Selection, input.Referrer)
	metadataJSON, err := json.Marshal(metadata)
	if err != nil {
		return nil, fmt.Errorf("item: capture bookmark: marshal metadata: %w", err)
	}

	query := fmt.Sprintf(`INSERT INTO items (owner_id, type, status, sensitivity, title, content_url, source_url, tags, source, metadata, auto_metadata)
		VALUES ($1, 'bookmark', 'pending', $2, $3, $4, $5, $6, $7, $8, '{}')
		RETURNING %s`, itemColumns)

	row := s.pool.QueryRow(ctx, query,
		ownerID, input.Sensitivity, input.Title, input.URL, input.URL, tags, input.Source, metadataJSON)

	it, err := scanItem(row)
	if err != nil {
		return nil, fmt.Errorf("item: capture bookmark: %w", err)
	}
	return it, nil
}

// buildBookmarkMetadata constructs a metadata map from optional bookmark provenance fields.
func buildBookmarkMetadata(selection, referrer *string) map[string]any {
	m := make(map[string]any)
	if selection != nil && *selection != "" {
		m["selection"] = *selection
	}
	if referrer != nil && *referrer != "" {
		m["referrer"] = *referrer
	}
	return m
