	sel := "selected text"
	ref := "https://referrer.example.com"

	t.Run("both selection and referrer", func(t *testing.T) {
		m := buildBookmarkMetadata(&sel, &ref)
		if m["selection"] != sel {
			t.Errorf("expected selection %q, got %v", sel, m["selection"])
		}
		if m["referrer"] != ref {
			t.Errorf("expected referrer %q, got %v", ref, m["referrer"])
		}
	})

	t.Run("selection only", func(t *testing.T) {
		m := buildBookmarkMetadata(&sel, nil)
		if m["selection"] != sel {
			t.Errorf("expected selection %q, got %v", sel, m["selection"])
		}
		if _, ok := m["referrer"]; ok {
			t.Error("expected no referrer key")
		}
	})

	t.Run("referrer only", func(t *testing.T) {
		m := buildBookmarkMetadata(nil, &ref)
		if _, ok := m["selection"]; ok {
			t.Error("expected no selection key")
		}
		if m["referrer"] != ref {
			t.Errorf("expected referrer %q, got %v", ref, m["referrer"])
		}
	})

	t.Run("neither", func(t *testing.T) {
		m := buildBookmarkMetadata(nil, nil)
		if len(m) != 0 {
			t.Errorf("expected empty metadata, got %v", m)
		}
	})

	t.Run("empty strings treated as absent", func(t *testing.T) {
		empty := ""
		m := buildBookmarkMetadata(&empty, &empty)
		if len(m) != 0 {
			t.Errorf("expected empty metadata for empty strings, got %v", m)
		}
	})
}

